+          this.renderChart(data, 'Thống kê hoạt động trên hồ sơ của bạn');
+        },
+        error: (err) => {
+          console.error('Lỗi tải thống kê:', err);
+          this.renderChart([0, 0], 'Thống kê hoạt động trên hồ sơ của bạn');
+        }
+      });
+  }
+
+  renderChart(data: number[], label: string) {
+    if (this.chart) {
+      this.chart.destroy(); // Xóa chart cũ
+    }
+
+    const config: ChartConfiguration = {
+      type: 'bar',
+      data: {
+        labels: this.barChartLabels,
+        datasets: [{
+          label: label,
+          data: data,
+          backgroundColor: ['#4CAF50', '#2196F3'],
+          borderColor: ['#388E3C', '#1976D2'],
+          borderWidth: 1
+        }]
+      },
+      options: {
+        responsive: true,
+        scales: {
+          y: {
+            beginAtZero: true,
+            ticks: {
+              stepSize: 1
+            }
+          }
+        },
+        plugins: {
+          tooltip: {
+            callbacks: {
+              afterLabel: (context) => {
+                const index = context.dataIndex;
+                const type = index === 0 ? 'PROFILE_VIEW' : 'INTERVIEW';
+                const recruiters = this.stats.recruiters[type] || [];
+                return recruiters.length > 0 ? `\nNhà tuyển dụng: ${recruiters.join(', ')}` : '';
+              }
+            }
+          }
+        }
+      }
+    };
+
+    this.chart = new Chart(this.barChartRef.nativeElement, config);
+  }
